mapper.select:
SELECT
    collected_at AS collectedAt,
    avg_tx_duration_sec AS avgTxDurationSec
FROM session_metrics_agg_1m
WHERE instance_id = #{instanceId}
AND database_id = #{databaseId}
AND collected_at >= CURRENT_TIMESTAMP - INTERVAL '30 minutes'
ORDER BY collected_at;

SELECT
    collected_at AS collectedAt,
    avg_lock_wait_sec AS avgLockWaitSec
FROM session_metrics_agg_1m
WHERE instance_id = #{instanceId}
AND database_id = #{databaseId}
AND collected_at >= CURRENT_TIMESTAMP - INTERVAL '30 minutes'
ORDER BY collected_at;
